import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import api from '../../utils/api';
import CommunitySetup from '../../components/CommunitySetup';

const CATEGORIES = ['Technology', 'Arts', 'Sports', 'Academic', 'Cultural', 'Business', 'Science', 'Social', 'Other'];

export default function CommunityAdminProfile() {
  const [community, setCommunity] = useState(null);
  const [noCommunity, setNoCommunity] = useState(false);
  const [form, setForm] = useState({});
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [activeTab, setActiveTab] = useState('edit');

  useEffect(() => {
    api.get('/communities/my/profile').then(res => {
      const c = res.data.data;
      setCommunity(c);
      setForm({
        name: c.name,
        description: c.description,
        category: c.category,
        logo: c.logo || '',
        coverImage: c.coverImage || '',
        socialLinks: c.socialLinks || {}
      });
    }).catch(err => {
      if (err.response?.status === 404) {
        setNoCommunity(true);
      } else {
        toast.error('Failed to load profile');
      }
    }).finally(() => setLoading(false));
  }, []);

  const set = (k, v) => setForm(p => ({ ...p, [k]: v }));
  const setSocial = (k, v) => setForm(p => ({ ...p, socialLinks: { ...p.socialLinks, [k]: v } }));

  const handleSave = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      await api.put(`/communities/${community._id}`, form);
      toast.success('Community profile updated!');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to update');
    } finally {
      setSaving(false);
    }
  };

  const getCategoryIcon = (category) => {
    const icons = {
      Technology: '💻',
      Arts: '🎨',
      Sports: '⚽',
      Academic: '📚',
      Cultural: '🎭',
      Business: '💼',
      Science: '🔬',
      Social: '🤝',
      Other: '🌟'
    };
    return icons[category] || '🏛️';
  };

  if (loading) return (
    <div className="loading-screen" style={{
      minHeight: '400px',
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'center',
      gap: '16px'
    }}>
      <div className="spinner" style={{ width: '40px', height: '40px', borderWidth: '3px' }} />
      <span style={{ color: 'var(--text-secondary)' }}>Loading community profile...</span>
    </div>
  );

  if (noCommunity) {
    return (
      <CommunitySetup onSetupComplete={(c) => {
        setCommunity(c);
        setNoCommunity(false);
        setForm({ name: c.name, description: c.description, category: c.category, logo: '', coverImage: '', socialLinks: {} });
      }} />
    );
  }

  return (
    <div className="page-wrapper" style={{ background: 'var(--bg-primary)', minHeight: '100vh' }}>
      <div className="container" style={{ maxWidth: 800, margin: '0 auto', padding: '32px 20px' }}>

        {/* Enhanced Header */}
        <div className="page-header" style={{ marginBottom: 32 }}>
          <div style={{ 
            display: 'flex', 
            justifyContent: 'space-between', 
            alignItems: 'flex-start',
            flexWrap: 'wrap',
            gap: '16px'
          }}>
            <div>
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '8px' }}>
                <div style={{ 
                  width: '48px', 
                  height: '48px', 
                  background: 'linear-gradient(135deg, var(--purple-primary), var(--pink-accent))',
                  borderRadius: 'var(--radius-md)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  fontSize: '24px'
                }}>
                  🏛️
                </div>
                <div>
                  <h2 style={{ fontFamily: 'var(--font-display)', margin: 0, fontSize: '1.75rem' }}>
                    COMMUNITY <span className="gradient-text">PROFILE</span>
                  </h2>
                  <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem', marginTop: '4px' }}>
                    Manage and customize your community information
                  </p>
                </div>
              </div>
            </div>
            <Link to="/community-admin" className="btn btn-outline" style={{ 
              display: 'flex',
              alignItems: 'center',
              gap: '8px'
            }}>
              <span>←</span> Dashboard
            </Link>
          </div>
        </div>

        {/* Enhanced Status Banner */}
        {community?.status !== 'approved' && (
          <div className={`alert alert-${community?.status === 'pending' ? 'warning' : 'danger'}`} style={{ 
            marginBottom: 24,
            borderRadius: 'var(--radius-md)',
            padding: '16px 20px',
            display: 'flex',
            alignItems: 'center',
            gap: '12px',
            background: community?.status === 'pending' ? 'rgba(245, 158, 11, 0.1)' : 'rgba(239, 68, 68, 0.1)',
            borderLeft: `4px solid ${community?.status === 'pending' ? 'var(--warning)' : '#ef4444'}`
          }}>
            <span style={{ fontSize: '1.5rem' }}>{community?.status === 'pending' ? '⏳' : '❌'}</span>
            <div>
              <strong>{community?.status === 'pending' ? 'Pending Approval' : 'Community Rejected'}</strong>
              <p style={{ margin: '4px 0 0 0', fontSize: '0.875rem' }}>
                {community?.status === 'pending' 
                  ? 'Your community is awaiting System Admin approval. You can still edit your profile while waiting.' 
                  : 'Your community was rejected. Please contact the system administrator for more information.'}
              </p>
            </div>
          </div>
        )}

        {/* Enhanced Main Card */}
        <div className="card" style={{ 
          marginBottom: 32,
          padding: 0,
          borderRadius: 'var(--radius-lg)',
          overflow: 'hidden',
          background: 'var(--bg-secondary)',
          border: '1px solid rgba(255,255,255,0.05)'
        }}>

          {/* Cover Image Section */}
          <div style={{ position: 'relative' }}>
            {form.coverImage ? (
              <div style={{ 
                height: '180px', 
                backgroundImage: `url(${form.coverImage})`,
                backgroundSize: 'cover',
                backgroundPosition: 'center',
                position: 'relative'
              }}>
                <div style={{
                  position: 'absolute',
                  bottom: '16px',
                  right: '16px',
                  background: 'rgba(0,0,0,0.7)',
                  padding: '4px 12px',
                  borderRadius: 'var(--radius-sm)',
                  fontSize: '0.75rem'
                }}>
                  Cover Image
                </div>
              </div>
            ) : (
              <div style={{ 
                height: '180px', 
                background: 'linear-gradient(135deg, var(--purple-primary), var(--cyan-accent), var(--pink-accent))',
                position: 'relative'
              }}>
                <div style={{
                  position: 'absolute',
                  bottom: '16px',
                  right: '16px',
                  background: 'rgba(0,0,0,0.5)',
                  padding: '4px 12px',
                  borderRadius: 'var(--radius-sm)',
                  fontSize: '0.75rem'
                }}>
                  No Cover Image
                </div>
              </div>
            )}

            {/* Profile Preview */}
            <div style={{ 
              padding: '0 32px 32px 32px',
              marginTop: '-60px',
              position: 'relative'
            }}>
              <div style={{ 
                display: 'flex', 
                alignItems: 'flex-end',
                gap: '24px',
                flexWrap: 'wrap'
              }}>
                <div
                  className="avatar avatar-xl"
                  style={{
                    width: '120px',
                    height: '120px',
                    fontSize: '3rem',
                    boxShadow: '0 8px 24px rgba(0,0,0,0.3)',
                    border: '4px solid var(--bg-secondary)',
                    background: form.logo ? `url(${form.logo})` : 'linear-gradient(135deg, var(--purple-primary), var(--cyan-accent))',
                    backgroundSize: 'cover',
                    backgroundPosition: 'center',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    borderRadius: 'var(--radius-lg)'
                  }}
                >
                  {!form.logo && form.name?.charAt(0)}
                </div>

                <div style={{ flex: 1, marginBottom: '8px' }}>
                  <div
                    style={{
                      fontFamily: 'var(--font-display)',
                      fontSize: '2rem',
                      marginBottom: '12px',
                      fontWeight: 'bold'
                    }}
                  >
                    {form.name || 'Community Name'}
                  </div>

                  <div style={{ display: 'flex', gap: '12px', flexWrap: 'wrap' }}>
                    <span className={`badge badge-${community?.status}`} style={{ 
                      background: community?.status === 'approved' ? 'linear-gradient(135deg, #10b981, #059669)' :
                                 community?.status === 'pending' ? 'linear-gradient(135deg, var(--warning), #f59e0b)' : 
                                 'linear-gradient(135deg, #ef4444, #dc2626)',
                      padding: '6px 12px',
                      display: 'flex',
                      alignItems: 'center',
                      gap: '6px'
                    }}>
                      {community?.status === 'approved' ? '✓ Approved' : 
                       community?.status === 'pending' ? '⏳ Pending' : '✗ Rejected'}
                    </span>
                    <span className={`badge badge-${form.category?.toLowerCase()}`} style={{ 
                      background: 'linear-gradient(135deg, var(--purple-primary), var(--pink-accent))',
                      padding: '6px 12px',
                      display: 'flex',
                      alignItems: 'center',
                      gap: '6px'
                    }}>
                      {getCategoryIcon(form.category)} {form.category}
                    </span>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Tabs */}
          <div style={{ 
            borderBottom: '1px solid rgba(255,255,255,0.1)',
            padding: '0 32px',
            display: 'flex',
            gap: '32px'
          }}>
            {[
              { id: 'edit', label: 'Edit Profile', icon: '✏️' },
              { id: 'preview', label: 'Preview', icon: '👁️' }
            ].map(tab => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                style={{
                  padding: '12px 0',
                  background: 'none',
                  border: 'none',
                  color: activeTab === tab.id ? 'var(--purple-light)' : 'var(--text-muted)',
                  cursor: 'pointer',
                  fontSize: '0.9rem',
                  fontWeight: activeTab === tab.id ? '600' : '400',
                  borderBottom: activeTab === tab.id ? `2px solid var(--purple-light)` : '2px solid transparent',
                  transition: 'all 0.2s',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px'
                }}
              >
                <span>{tab.icon}</span> {tab.label}
              </button>
            ))}
          </div>

          {/* Content */}
          <div style={{ padding: '32px' }}>
            {activeTab === 'edit' ? (
              <form onSubmit={handleSave}>
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
                  <div className="form-group">
                    <label className="form-label" style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                      <span>🏷️</span> Community Name *
                    </label>
                    <input 
                      className="form-control" 
                      value={form.name || ''} 
                      onChange={e => set('name', e.target.value)} 
                      required 
                      style={{ padding: '12px', transition: '0.2s' }}
                      placeholder="Enter community name"
                    />
                  </div>
                  <div className="form-group">
                    <label className="form-label" style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                      <span>📂</span> Category *
                    </label>
                    <select 
                      className="form-control" 
                      value={form.category || ''} 
                      onChange={e => set('category', e.target.value)}
                      style={{ padding: '12px' }}
                    >
                      {CATEGORIES.map(c => (
                        <option key={c} value={c}>
                          {getCategoryIcon(c)} {c}
                        </option>
                      ))}
                    </select>
                  </div>
                </div>

                <div className="form-group">
                  <label className="form-label" style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                    <span>📝</span> Description *
                  </label>
                  <textarea 
                    className="form-control" 
                    rows={5} 
                    value={form.description || ''} 
                    onChange={e => set('description', e.target.value)} 
                    required 
                    style={{ 
                      resize: 'vertical', 
                      padding: '12px',
                      lineHeight: '1.6',
                      transition: '0.2s'
                    }}
                    placeholder="Describe your community's purpose, activities, and goals..."
                  />
                </div>

                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
                  <div className="form-group">
                    <label className="form-label" style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                      <span>🖼️</span> Logo URL
                    </label>
                    <input 
                      className="form-control" 
                      value={form.logo || ''} 
                      onChange={e => set('logo', e.target.value)} 
                      placeholder="https://..."
                      style={{ padding: '12px' }}
                    />
                    {form.logo && (
                      <div style={{ marginTop: '8px', fontSize: '0.75rem', color: 'var(--text-muted)' }}>
                        ✓ Logo URL provided
                      </div>
                    )}
                  </div>
                  <div className="form-group">
                    <label className="form-label" style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                      <span>🎨</span> Cover Image URL
                    </label>
                    <input 
                      className="form-control" 
                      value={form.coverImage || ''} 
                      onChange={e => set('coverImage', e.target.value)} 
                      placeholder="https://..."
                      style={{ padding: '12px' }}
                    />
                  </div>
                </div>

                <div style={{ marginBottom: '28px' }}>
                  <label className="form-label" style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '12px' }}>
                    <span>🔗</span> Social Links
                  </label>
                  <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '12px' }}>
                    {[
                      { key: 'website', label: '🌐 Website', placeholder: 'https://...' },
                      { key: 'facebook', label: '📘 Facebook', placeholder: 'https://facebook.com/...' },
                      { key: 'instagram', label: '📷 Instagram', placeholder: 'https://instagram.com/...' },
                      { key: 'twitter', label: '🐦 Twitter', placeholder: 'https://twitter.com/...' }
                    ].map(s => (
                      <div key={s.key}>
                        <label className="form-label" style={{ fontSize: '0.75rem', textTransform: 'capitalize' }}>{s.label}</label>
                        <input 
                          className="form-control" 
                          value={form.socialLinks?.[s.key] || ''} 
                          onChange={e => setSocial(s.key, e.target.value)} 
                          placeholder={s.placeholder}
                          style={{ padding: '10px', fontSize: '0.85rem' }}
                        />
                      </div>
                    ))}
                  </div>
                </div>

                <button 
                  type="submit" 
                  className="btn btn-primary" 
                  style={{ 
                    width: '100%', 
                    justifyContent: 'center', 
                    padding: '14px',
                    fontSize: '1rem',
                    fontWeight: 600,
                    background: 'linear-gradient(135deg, var(--purple-primary), var(--pink-accent))',
                    transition: 'transform 0.2s',
                    transform: saving ? 'scale(0.98)' : 'scale(1)'
                  }} 
                  disabled={saving}
                >
                  {saving ? (
                    <span style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                      <span className="spinner" style={{ width: '16px', height: '16px', borderWidth: '2px' }} />
                      Saving Changes...
                    </span>
                  ) : (
                    <span style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                      💾 Save Profile Changes
                    </span>
                  )}
                </button>
              </form>
            ) : (
              <div style={{ padding: '20px', background: 'var(--bg-elevated)', borderRadius: 'var(--radius-md)' }}>
                <h4 style={{ marginBottom: '16px', color: 'var(--purple-light)' }}>Community Preview</h4>
                <div style={{ 
                  background: 'var(--bg-primary)', 
                  padding: '20px', 
                  borderRadius: 'var(--radius-md)',
                  border: '1px solid rgba(255,255,255,0.1)'
                }}>
                  <div style={{ marginBottom: '16px' }}>
                    <strong style={{ color: 'var(--purple-light)' }}>Name:</strong> {form.name || 'Not set'}
                  </div>
                  <div style={{ marginBottom: '16px' }}>
                    <strong style={{ color: 'var(--purple-light)' }}>Category:</strong> {form.category ? `${getCategoryIcon(form.category)} ${form.category}` : 'Not set'}
                  </div>
                  <div style={{ marginBottom: '16px' }}>
                    <strong style={{ color: 'var(--purple-light)' }}>Description:</strong>
                    <p style={{ marginTop: '8px', color: 'var(--text-secondary)' }}>{form.description || 'No description provided'}</p>
                  </div>
                  {Object.keys(form.socialLinks || {}).filter(k => form.socialLinks[k]).length > 0 && (
                    <div>
                      <strong style={{ color: 'var(--purple-light)' }}>Social Links:</strong>
                      <div style={{ marginTop: '8px', display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
                        {Object.entries(form.socialLinks).map(([key, value]) => value && (
                          <a key={key} href={value} target="_blank" rel="noopener noreferrer" 
                             style={{ color: 'var(--cyan-accent)', textDecoration: 'none', fontSize: '0.85rem' }}>
                            {key} →
                          </a>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Enhanced Stats Card */}
        <div className="card" style={{ padding: '24px' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '20px' }}>
            <span style={{ fontSize: '1.5rem' }}>📊</span>
            <h4 style={{ fontFamily: 'var(--font-display)', margin: 0, fontSize: '1.1rem' }}>COMMUNITY STATISTICS</h4>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))', gap: '16px' }}>
            {[
              { label: 'Total Members', value: community?.members?.length || 0, icon: '👥', color: 'var(--purple-light)' },
              { label: 'Events', value: community?.events?.length || 0, icon: '📅', color: 'var(--cyan-accent)' },
              { label: 'Created', value: new Date(community?.createdAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }), icon: '🎂', color: 'var(--pink-accent)' },
              { label: 'Status', value: community?.status === 'approved' ? 'Active' : community?.status === 'pending' ? 'Pending' : 'Rejected', icon: '⚡', color: community?.status === 'approved' ? '#10b981' : 'var(--warning)' }
            ].map((s, i) => (
              <div key={i} style={{ 
                textAlign: 'center', 
                padding: '20px', 
                background: 'var(--bg-elevated)', 
                borderRadius: 'var(--radius-md)',
                transition: 'transform 0.2s'
              }}>
                <div style={{ fontSize: '2rem', marginBottom: '8px' }}>{s.icon}</div>
                <div style={{ fontFamily: 'var(--font-display)', fontSize: '1.5rem', color: s.color, fontWeight: 'bold' }}>{s.value}</div>
                <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.08em', marginTop: '8px' }}>{s.label}</div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}
